#include <bits/stdc++.h>
using namespace std;
int main(){
    int t,n,m,a[10001],len;
    cin>>t;
    for(int i=0;i<t;i++){
    	cin>>n>>m;
    	long long ans=0;
    	for(int i=0;i<10001;i++)a[i]=0;
    	a[1]=1;len=1;
    	int j,z;
    	for(j=2;j<=n;j++){
        	int x=0;
            for(z=1;z<=len;z++){
                a[z]=a[z]*j+x;
                x=a[z]/10;
                a[z]%=10;
            }
            while(x>0){
            	a[z]=x%10;
            	x=x/10;
            	z++;
			}
			len=z-1;
        }
        //for(int i=len;i>0;i--){
        //	if(a[i]==m)cout<<' '<<a[i]<<' ';
        //	else cout<<a[i];
		//}
        //cout<<endl;
        for(int i=len;i>0;i--)if(a[i]==m)ans++;
        cout<<ans;
        if(i<t-1)cout<<endl;
	}
    return 0;
}
